/* ---------------------------------------------------------------------------
 * ChatMessageList — suite 19/P01
 * Placeholder shell for the message stream. Population (rendering messages,
 * citations, streaming chunks) lands in 19/P02.
 * --------------------------------------------------------------------------- */

export type ChatMessage = {
  id: string;
  role: "user" | "assistant";
  content: string;
};

type ChatMessageListProps = {
  messages?: ChatMessage[];
};

export default function ChatMessageList({ messages = [] }: ChatMessageListProps) {
  return (
    <div
      className="chat-messages"
      role="log"
      aria-live="polite"
      aria-label="Conversation"
    >
      {messages.length === 0 ? (
        <p className="chat-messages__empty">no messages yet &mdash; ask anything below.</p>
      ) : null}
    </div>
  );
}

