import { z } from "zod";

export const chatMessageSchema = z.object({
  role: z.enum(["user", "assistant"]),
  content: z.string().min(1).max(4000),
});

export const chatRequestSchema = z
  .object({
    messages: z.array(chatMessageSchema).min(1).max(40),
    topicHints: z.array(z.string()).optional(),
  })
  .refine((req) => req.messages[req.messages.length - 1]?.role === "user", {
    message: "latest message must have role 'user'",
    path: ["messages"],
  });

export type ChatMessage = z.infer<typeof chatMessageSchema>;
export type ChatRequest = z.infer<typeof chatRequestSchema>;

export type ChatMetaPayload = {
  citations: { id: string; chunkId: string; snippet: string }[];
  usage: { inputTokens?: number; outputTokens?: number };
  retrievedCount: number;
};

export type ChatErrorBody = {
  error: string;
  detail?: string;
};

import { defineConfig } from "vitest/config";
import path from "node:path";

export default defineConfig({
  oxc: {
    jsx: { runtime: "automatic" },
  },
  test: {
    environment: "jsdom",
    include: ["src/**/*.test.{ts,tsx}", "scripts/**/*.test.{ts,tsx}"],
    exclude: [
      "node_modules/**",
      "e2e/**",
      "_archive_operator/**",
      "_archive_nashlab/**",
      "_archive_prompts_pre_overhaul_2026-04-25/**",
      "src/_legacy_v1/**",
    ],
    globals: true,
    setupFiles: ["src/components/primitives/__tests__/setup.ts"],
  },
  resolve: {
    alias: {
      "@": path.resolve(__dirname, "src"),
    },
  },
});

