export default function ChatHeader() {
  return (
    <header className="chat-header">
      <h1 className="chat-header__heading">Ask my LLM about my work</h1>
      <p className="chat-header__subhead">
        A retrieval-augmented assistant grounded in my essays, project notes, and
        public writing. It cites the corpus, answers in my voice, and admits
        when it doesn&rsquo;t know &mdash; it isn&rsquo;t me, and shouldn&rsquo;t pretend to be.
      </p>
      <p className="chat-header__meta">
        <a href="/about#llm" className="chat-header__link">
          What&rsquo;s grounding this &rarr;
        </a>
      </p>
    </header>
  );
