            "a",
            { key: nextKey(), href: link[2], className: "md-link" },
            ...parseInline(link[1]),
          ),
        );
        i += link[0].length;
        continue;
      }
    }

    buf += ch;
    i++;
  }

  flush();
  return out;
}

function renderBlock(b: Block, idx: number): ReactNode {
  const key = `mb-${idx}`;
  switch (b.type) {
    case "p":
      return createElement(
        "p",
        { key, className: "md-p" },
        ...parseInline(b.text),
      );
    case "heading":
      return createElement(
        "p",
        { key, className: "md-p md-p--heading", "data-md-heading": b.level },
        createElement("strong", null, ...parseInline(b.text)),
      );
    case "code":
      return createElement(
        "pre",
        { key, className: "md-pre" },
        createElement(
          "code",
          {
            className: "md-codeblock",
            "data-lang": b.lang ?? null,
          },
          b.content,
        ),
      );
    case "ul":
      return createElement(
        "ul",
        { key, className: "md-ul" },
        ...b.items.map((it, j) =>
          createElement(
            "li",
            { key: `${key}-${j}`, className: "md-li" },
            ...parseInline(it),
          ),
        ),
      );
    case "ol":
      return createElement(
        "ol",
        { key, className: "md-ol" },
        ...b.items.map((it, j) =>
          createElement(
            "li",
            { key: `${key}-${j}`, className: "md-li" },
            ...parseInline(it),
          ),
        ),
      );
  }
}

export function renderMarkdown(src: string): ReactNode {
  inlineKeyCounter = 0;
  const blocks = parseBlocks(src);
  return createElement(
    Fragment,
    null,
    ...blocks.map((b, i) => renderBlock(b, i)),
  );
}

